// Astra Security SDK v1.0.0
// https://astra.security

(function(window, document) {
    'use strict';
    
    // Configuration
    const SDK_VERSION = '1.0.0';
    const API_BASE_URL = 'https://api.astra.security/v1';
    const COLLECTION_INTERVAL = 60000; // 1 minute
    const MAX_BATCH_SIZE = 100;
    
    // Analytics data storage
    let analyticsQueue = [];
    let sessionId = null;
    let initialized = false;
    let apiKey = null;
    let config = {};
    
    // Generate session ID
    function generateSessionId() {
        return 'session_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
    }
    
    // Collect page data
    function collectPageData() {
        return {
            url: window.location.href,
            referrer: document.referrer,
            title: document.title,
            language: navigator.language,
            userAgent: navigator.userAgent,
            screen: {
                width: window.screen.width,
                height: window.screen.height,
                colorDepth: window.screen.colorDepth
            },
            viewport: {
                width: window.innerWidth,
                height: window.innerHeight
            },
            timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
            timestamp: new Date().toISOString()
        };
    }
    
    // Collect performance data
    function collectPerformanceData() {
        if (!window.performance || !window.performance.timing) {
            return null;
        }
        
        const timing = window.performance.timing;
        const navigation = window.performance.navigation || {};
        
        return {
            navigationType: navigation.type || 0,
            redirectCount: navigation.redirectCount || 0,
            timing: {
                navigationStart: timing.navigationStart,
                redirectStart: timing.redirectStart,
                redirectEnd: timing.redirectEnd,
                fetchStart: timing.fetchStart,
                domainLookupStart: timing.domainLookupStart,
                domainLookupEnd: timing.domainLookupEnd,
                connectStart: timing.connectStart,
                connectEnd: timing.connectEnd,
                secureConnectionStart: timing.secureConnectionStart,
                requestStart: timing.requestStart,
                responseStart: timing.responseStart,
                responseEnd: timing.responseEnd,
                domLoading: timing.domLoading,
                domInteractive: timing.domInteractive,
                domContentLoadedEventStart: timing.domContentLoadedEventStart,
                domContentLoadedEventEnd: timing.domContentLoadedEventEnd,
                domComplete: timing.domComplete,
                loadEventStart: timing.loadEventStart,
                loadEventEnd: timing.loadEventEnd
            }
        };
    }
    
    // Collect security data
    function collectSecurityData() {
        const security = {
            https: window.location.protocol === 'https:',
            cookiesEnabled: navigator.cookieEnabled,
            localStorage: typeof window.localStorage !== 'undefined',
            sessionStorage: typeof window.sessionStorage !== 'undefined',
            indexedDB: typeof window.indexedDB !== 'undefined',
            serviceWorker: 'serviceWorker' in navigator,
            webRTC: 'RTCPeerConnection' in window,
            webGL: (function() {
                try {
                    const canvas = document.createElement('canvas');
                    return !!(window.WebGLRenderingContext && 
                             (canvas.getContext('webgl') || canvas.getContext('experimental-webgl')));
                } catch(e) {
                    return false;
                }
            })(),
            webAudio: 'AudioContext' in window || 'webkitAudioContext' in window,
            geolocation: 'geolocation' in navigator,
            notifications: 'Notification' in window,
            pushManager: 'PushManager' in window,
            credentials: 'credentials' in navigator,
            paymentRequest: 'PaymentRequest' in window
        };
        
        return security;
    }
    
    // Collect network data
    function collectNetworkData() {
        const connection = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
        
        if (!connection) {
            return null;
        }
        
        return {
            effectiveType: connection.effectiveType,
            downlink: connection.downlink,
            rtt: connection.rtt,
            saveData: connection.saveData,
            type: connection.type
        };
    }
    
    // Collect error data
    function collectErrorData(error) {
        return {
            message: error.message,
            filename: error.filename || '',
            lineno: error.lineno || 0,
            colno: error.colno || 0,
            stack: error.stack || '',
            timestamp: new Date().toISOString()
        };
    }
    
    // Send analytics batch
    function sendAnalyticsBatch() {
        if (analyticsQueue.length === 0 || !apiKey) {
            return;
        }
        
        const batch = analyticsQueue.splice(0, MAX_BATCH_SIZE);
        
        fetch(API_BASE_URL + '/analytics', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': 'Bearer ' + apiKey,
                'X-Astra-SDK-Version': SDK_VERSION
            },
            body: JSON.stringify({
                sessionId: sessionId,
                events: batch,
                timestamp: new Date().toISOString()
            })
        })
        .then(response => {
            if (!response.ok) {
                console.warn('[Astra] Failed to send analytics:', response.status);
                // Requeue failed batch
                analyticsQueue = batch.concat(analyticsQueue);
            }
        })
        .catch(error => {
            console.warn('[Astra] Error sending analytics:', error);
            // Requeue failed batch
            analyticsQueue = batch.concat(analyticsQueue);
        });
    }
    
    // Queue analytics event
    function queueAnalyticsEvent(type, data) {
        analyticsQueue.push({
            type: type,
            data: data,
            timestamp: new Date().toISOString()
        });
        
        // Send batch if we have enough events
        if (analyticsQueue.length >= MAX_BATCH_SIZE) {
            sendAnalyticsBatch();
        }
    }
    
    // Initialize error tracking
    function initErrorTracking() {
        // Global error handler
        window.addEventListener('error', function(event) {
            queueAnalyticsEvent('error', collectErrorData(event.error || event));
        });
        
        // Promise rejection handler
        window.addEventListener('unhandledrejection', function(event) {
            queueAnalyticsEvent('promise_rejection', {
                reason: event.reason ? event.reason.toString() : 'Unknown',
                timestamp: new Date().toISOString()
            });
        });
        
        // Console error tracking
        if (config.trackConsoleErrors) {
            const originalConsoleError = console.error;
            console.error = function() {
                queueAnalyticsEvent('console_error', {
                    message: Array.from(arguments).join(' '),
                    timestamp: new Date().toISOString()
                });
                originalConsoleError.apply(console, arguments);
            };
        }
    }
    
    // Initialize performance tracking
    function initPerformanceTracking() {
        if (window.performance && window.performance.timing) {
            window.addEventListener('load', function() {
                setTimeout(function() {
                    const perfData = collectPerformanceData();
                    if (perfData) {
                        queueAnalyticsEvent('performance', perfData);
                    }
                }, 0);
            });
        }
        
        // Core Web Vitals
        if ('PerformanceObserver' in window) {
            // LCP
            try {
                const lcpObserver = new PerformanceObserver((entryList) => {
                    const entries = entryList.getEntries();
                    const lastEntry = entries[entries.length - 1];
                    queueAnalyticsEvent('lcp', {
                        value: lastEntry.startTime,
                        element: lastEntry.element ? lastEntry.element.tagName : null,
                        timestamp: new Date().toISOString()
                    });
                });
                lcpObserver.observe({type: 'largest-contentful-paint', buffered: true});
            } catch(e) {}
            
            // FID
            try {
                const fidObserver = new PerformanceObserver((entryList) => {
                    const entries = entryList.getEntries();
                    entries.forEach(entry => {
                        queueAnalyticsEvent('fid', {
                            value: entry.processingStart - entry.startTime,
                            timestamp: new Date().toISOString()
                        });
                    });
                });
                fidObserver.observe({type: 'first-input', buffered: true});
            } catch(e) {}
            
            // CLS
            try {
                let clsValue = 0;
                let clsEntries = [];
                
                const clsObserver = new PerformanceObserver((entryList) => {
                    for (const entry of entryList.getEntries()) {
                        if (!entry.hadRecentInput) {
                            clsValue += entry.value;
                            clsEntries.push(entry);
                        }
                    }
                });
                
                clsObserver.observe({type: 'layout-shift', buffered: true});
                
                // Report CLS on visibility change
                document.addEventListener('visibilitychange', () => {
                    if (document.visibilityState === 'hidden') {
                        queueAnalyticsEvent('cls', {
                            value: clsValue,
                            entries: clsEntries.length,
                            timestamp: new Date().toISOString()
                        });
                    }
                });
            } catch(e) {}
        }
    }
    
    // Initialize user interaction tracking
    function initInteractionTracking() {
        if (config.trackInteractions) {
            let interactionStart = null;
            
            document.addEventListener('click', function(event) {
                const target = event.target;
                const elementData = {
                    tagName: target.tagName,
                    id: target.id,
                    className: target.className,
                    text: target.textContent ? target.textContent.substring(0, 100) : '',
                    href: target.href || '',
                    x: event.clientX,
                    y: event.clientY
                };
                
                queueAnalyticsEvent('click', elementData);
            });
            
            document.addEventListener('keydown', function(event) {
                if (event.key === 'Enter' || event.key === ' ') {
                    queueAnalyticsEvent('key_interaction', {
                        key: event.key,
                        target: event.target.tagName,
                        timestamp: new Date().toISOString()
                    });
                }
            });
            
            // Form submissions
            document.addEventListener('submit', function(event) {
                const form = event.target;
                queueAnalyticsEvent('form_submit', {
                    formId: form.id,
                    action: form.action,
                    method: form.method,
                    timestamp: new Date().toISOString()
                });
            });
        }
    }
    
    // Initialize network monitoring
    function initNetworkMonitoring() {
        if (config.monitorNetwork) {
            const networkData = collectNetworkData();
            if (networkData) {
                queueAnalyticsEvent('network_info', networkData);
                
                // Monitor network changes
                const connection = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
                if (connection) {
                    connection.addEventListener('change', function() {
                        queueAnalyticsEvent('network_change', collectNetworkData());
                    });
                }
            }
        }
    }
    
    // Initialize security monitoring
    function initSecurityMonitoring() {
        if (config.monitorSecurity) {
            const securityData = collectSecurityData();
            queueAnalyticsEvent('security_info', securityData);
            
            // Monitor for potential security issues
            window.addEventListener('securitypolicyviolation', function(event) {
                queueAnalyticsEvent('csp_violation', {
                    violatedDirective: event.violatedDirective,
                    effectiveDirective: event.effectiveDirective,
                    sourceFile: event.sourceFile,
                    lineNumber: event.lineNumber,
                    columnNumber: event.columnNumber,
                    blockedURI: event.blockedURI,
                    timestamp: new Date().toISOString()
                });
            });
        }
    }
    
    // Periodic data collection
    function startPeriodicCollection() {
        setInterval(function() {
            // Collect page data periodically
            queueAnalyticsEvent('page_heartbeat', collectPageData());
            
            // Send any queued analytics
            if (analyticsQueue.length > 0) {
                sendAnalyticsBatch();
            }
        }, COLLECTION_INTERVAL);
    }
    
    // Public API
    const Astra = function(options) {
        if (!options || !options.apiKey) {
            throw new Error('Astra SDK requires an apiKey');
        }
        
        apiKey = options.apiKey;
        config = {
            trackConsoleErrors: options.trackConsoleErrors !== false,
            trackInteractions: options.trackInteractions !== false,
            monitorNetwork: options.monitorNetwork !== false,
            monitorSecurity: options.monitorSecurity !== false,
            ...options
        };
        
        return this;
    };
    
    Astra.prototype.init = function() {
        if (initialized) {
            console.warn('[Astra] SDK already initialized');
            return this;
        }
        
        sessionId = generateSessionId();
        initialized = true;
        
        // Initial data collection
        queueAnalyticsEvent('session_start', {
            sessionId: sessionId,
            pageData: collectPageData(),
            securityData: collectSecurityData(),
            networkData: collectNetworkData()
        });
        
        // Initialize tracking
        initErrorTracking();
        initPerformanceTracking();
        initInteractionTracking();
        initNetworkMonitoring();
        initSecurityMonitoring();
        
        // Start periodic collection
        startPeriodicCollection();
        
        // Send initial batch
        setTimeout(sendAnalyticsBatch, 1000);
        
        console.log('[Astra] SDK initialized successfully');
        return this;
    };
    
    Astra.prototype.track = function(eventName, eventData) {
        if (!initialized) {
            console.warn('[Astra] SDK not initialized. Call init() first.');
            return this;
        }
        
        queueAnalyticsEvent('custom_' + eventName, {
            name: eventName,
            data: eventData,
            timestamp: new Date().toISOString()
        });
        
        return this;
    };
    
    Astra.prototype.identify = function(userId, traits) {
        if (!initialized) {
            console.warn('[Astra] SDK not initialized. Call init() first.');
            return this;
        }
        
        queueAnalyticsEvent('identify', {
            userId: userId,
            traits: traits,
            timestamp: new Date().toISOString()
        });
        
        return this;
    };
    
    Astra.prototype.page = function(pageName, properties) {
        if (!initialized) {
            console.warn('[Astra] SDK not initialized. Call init() first.');
            return this;
        }
        
        queueAnalyticsEvent('page_view', {
            name: pageName,
            properties: properties,
            pageData: collectPageData(),
            timestamp: new Date().toISOString()
        });
        
        return this;
    };
    
    Astra.prototype.flush = function() {
        sendAnalyticsBatch();
        return this;
    };
    
    Astra.prototype.getSessionId = function() {
        return sessionId;
    };
    
    // Expose to window
    window.Astra = Astra;
    
    // Auto-initialize if data attribute is present
    document.addEventListener('DOMContentLoaded', function() {
        const script = document.currentScript;
        if (script && script.dataset.apiKey) {
            try {
                const astra = new Astra({
                    apiKey: script.dataset.apiKey,
                    trackConsoleErrors: script.dataset.trackConsoleErrors !== 'false',
                    trackInteractions: script.dataset.trackInteractions !== 'false',
                    monitorNetwork: script.dataset.monitorNetwork !== 'false',
                    monitorSecurity: script.dataset.monitorSecurity !== 'false'
                });
                astra.init();
                window.astra = astra;
            } catch(error) {
                console.error('[Astra] Auto-initialization failed:', error);
            }
        }
    });
    
})(window, document);